// Get current time in IST
const now = new Date();
const istOffset = 5.5 * 60 * 60 * 1000;
const istNow = new Date(now.getTime() + istOffset);

const currentDay = String(istNow.getUTCDate()).padStart(2, '0');
const currentMonth = String(istNow.getUTCMonth() + 1).padStart(2, '0');
const currentYear = istNow.getUTCFullYear();
const currentHour = istNow.getUTCHours();
const currentMinute = istNow.getUTCMinutes();

const currentDate = `${currentDay}/${currentMonth}/${currentYear}`;
const currentTime = `${String(currentHour).padStart(2, '0')}:${String(currentMinute).padStart(2, '0')}`;

console.log(`[SCHEDULER] Checking at ${currentDate} ${currentTime}`);

const items = $input.all();
const toTrigger = [];

for (const item of items) {
  const row = item.json;

  // Get interview date/time from column I (Interview date)
  const interviewDateTime = row['Interview date'] || '';
  if (!interviewDateTime) continue;

  // Get interview type from column K (Interview type)
  const interviewType = (row['Interview type'] || '').toLowerCase();
  const isAiCall = interviewType.includes('ai') && (interviewType.includes('call') || interviewType.includes('voice') || interviewType.includes('agent'));

  if (!isAiCall) continue;

  // Parse date and time from format: "30/03/2026, 11:14 am"
  const parts = interviewDateTime.split(',').map(s => s.trim());
  const datePart = parts[0] || '';
  const timePart = parts[1] || '';

  // Check if date matches
  if (datePart !== currentDate) continue;

  // Parse time
  const timeMatch = timePart.toUpperCase().match(/(\d{1,2}):(\d{2})\s*(AM|PM)?/i);
  if (!timeMatch) continue;

  let intHour = parseInt(timeMatch[1]);
  const intMinute = parseInt(timeMatch[2]);
  const ampm = timeMatch[3];

  if (ampm === 'PM' && intHour !== 12) intHour += 12;
  if (ampm === 'AM' && intHour === 12) intHour = 0;

  // Check if time matches (within current minute)
  if (intHour !== currentHour || intMinute !== currentMinute) continue;

  console.log(`[SCHEDULER] MATCH FOUND: ${row['Name of the Candidate']} at ${timePart}`);

  toTrigger.push({
    json: {
      candidateName: row['Name of the Candidate'] || '',
      email: row['Email'] || '',
      role: row['Role'] || '',
      logId: row['Log ID'] || '',
      rowId: row['Row ID'] || row['row_id'] || '',
      contact: row['Contact Number'] || '',
      cv: row['CV'] || '',
      summary: row['Summary'] || '',
      score: row['Score'] || '',
      status: row['Status'] || '',
      interviewDate: interviewDateTime,
      interviewType: row['Interview type'] || '',
      meetingLink: row['Meeting link'] || '',
      location: row['Location'] || '',
      department: row['Department'] || '',
      position: row['Position'] || ''
    }
  });
}

if (toTrigger.length === 0) {
  console.log('[SCHEDULER] No matches found');
}

return toTrigger;
